#include<bits/stdc++.h>
using namespace std;
int solve()
{
    string s;
    char c;
    int x, ans = 0;
    while (cin>>c)
    {
        if (c == 'R') 
        {
        	string s;
        	cin >> s >> x >> c;
            ans += x * solve();
        }
        if (c=='B') 
        	cin >> c >> x, ans -= x;
    	if (c=='F') 
    		cin >> c >> x, ans += x;
    	if (c == ']') return ans;
    }
    return ans;
}
int main()
{
    cout<<abs(solve());
    return 0;
}
